    when(opDict.hasPrefixOperator(anyString())).thenReturn(false);
    when(opDict.hasPostfixOperator(anyString())).thenReturn(false);
    when(opDict.hasInfixOperator(anyString())).thenReturn(false);

    String expr = "0xFa";
